import React, { useState } from "react";

const AnadirSede = () => {
  const [formulario, setFormulario] = useState({
    zona: "",
    calle: "",
    referencias: "",
    nombre_edificio: "",
    longitud: "",
    latitud: "",
  });

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormulario({
      ...formulario,
      [name]: value,
    });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    console.log("Datos de la ubicación:", formulario);
    alert("Ubicación registrada correctamente (solo frontend)");
  };

  return (
    <div className="p-6">
      <h2 className="text-2xl font-bold mb-4">Añadir Ubicación</h2>
      <form onSubmit={handleSubmit} className="space-y-4">

        <div>
          <label className="block font-medium">Zona</label>
          <input
            type="text"
            name="zona"
            value={formulario.zona}
            onChange={handleChange}
            maxLength={50}
            className="w-full border border-gray-300 rounded p-2"
            required
          />
        </div>

        <div>
          <label className="block font-medium">Calle</label>
          <input
            type="text"
            name="calle"
            value={formulario.calle}
            onChange={handleChange}
            maxLength={50}
            className="w-full border border-gray-300 rounded p-2"
            required
          />
        </div>

        <div>
          <label className="block font-medium">Referencias</label>
          <textarea
            name="referencias"
            value={formulario.referencias}
            onChange={handleChange}
            maxLength={500}
            className="w-full border border-gray-300 rounded p-2"
          />
        </div>

        <div>
          <label className="block font-medium">Nombre del Edificio</label>
          <input
            type="text"
            name="nombre_edificio"
            value={formulario.nombre_edificio}
            onChange={handleChange}
            maxLength={100}
            className="w-full border border-gray-300 rounded p-2"
          />
        </div>

        <div>
          <label className="block font-medium">Longitud</label>
          <input
            type="number"
            name="longitud"
            value={formulario.longitud}
            onChange={handleChange}
            step="0.0000000001"
            className="w-full border border-gray-300 rounded p-2"
            required
          />
        </div>

        <div>
          <label className="block font-medium">Latitud</label>
          <input
            type="number"
            name="latitud"
            value={formulario.latitud}
            onChange={handleChange}
            step="0.0000000001"
            className="w-full border border-gray-300 rounded p-2"
            required
          />
        </div>

        <button
          type="submit"
          className="bg-emerald-600 text-white px-4 py-2 rounded hover:bg-emerald-700"
        >
          Guardar Ubicación
        </button>
      </form>
    </div>
  );
};

export default AnadirSede;
